// ════════════════════════════════════════════════════════
// TOOL: BUSCAR DISPONIBILIDADE
// Consulta horários disponíveis de um profissional
// Replica a lógica do AgendamentoService.getHorariosDisponiveis()
// ════════════════════════════════════════════════════════

const input = $input.item.json;
const query = input.query || '';
const organizacaoId = input.organizacao_id || input.organizacaoId;
let funcionarioId = input.funcionario_id || input.funcionarioId;
let servicoId = input.servico_id || input.servicoId;
let dataDesejada = input.data || input.dataDesejada || null;

// Tentar extrair IDs do query
if (query) {
  if (!funcionarioId) {
    const fMatch = query.match(/funcionario[_\s]?(?:id)?[:\s]*(\d+)/i);
    if (fMatch) funcionarioId = fMatch[1];
  }
  if (!servicoId) {
    const sMatch = query.match(/servico[_\s]?(?:id)?[:\s]*(\d+)/i);
    if (sMatch) servicoId = sMatch[1];
  }
  if (!dataDesejada) {
    // Tentar formato YYYY-MM-DD
    const dMatch = query.match(/(\d{4}-\d{2}-\d{2})/);
    if (dMatch) {
      dataDesejada = dMatch[1];
    } else {
      // Tentar formato DD/MM/YYYY
      const dMatch2 = query.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
      if (dMatch2) {
        dataDesejada = `${dMatch2[3]}-${dMatch2[2].padStart(2, '0')}-${dMatch2[1].padStart(2, '0')}`;
      }
    }
  }
}

if (!funcionarioId) {
  return [{ json: { error: true, message: 'funcionario_id não informado. Primeiro selecione um profissional.' } }];
}
if (!servicoId) {
  return [{ json: { error: true, message: 'servico_id não informado. Primeiro selecione um serviço.' } }];
}
if (!organizacaoId) {
  return [{ json: { error: true, message: 'organizacao_id não informado.' } }];
}

// Se não informou data, buscar próximos 3 dias úteis
const buscarProximosDias = !dataDesejada;

return [{
  json: {
    funcionario_id: funcionarioId,
    servico_id: servicoId,
    organizacao_id: organizacaoId,
    data_desejada: dataDesejada,
    buscar_proximos_dias: buscarProximosDias
  }
}];

// ════════════════════════════════════════════════════════
// PREPARAR DATAS PARA CONSULTA
// Se data específica: usar essa data
// Se sem data: gerar lista dos próximos 3 dias úteis
// ════════════════════════════════════════════════════════

const params = $('Extrair Parâmetros').item.json;
const duracaoServico = $('Buscar Duração Serviço').item.json.duracao || 30;
const tolerancia = $input.item.json.tolerancia || 15;

const DIAS_SEMANA = ['DOMINGO', 'SEGUNDA', 'TERCA', 'QUARTA', 'QUINTA', 'SEXTA', 'SABADO'];
const DIAS_SEMANA_PT = ['Domingo', 'Segunda-feira', 'Terça-feira', 'Quarta-feira', 'Quinta-feira', 'Sexta-feira', 'Sábado'];

let datasParaConsultar = [];

if (params.data_desejada) {
  // Data específica informada
  const d = new Date(params.data_desejada + 'T12:00:00');
  datasParaConsultar.push({
    iso: params.data_desejada,
    diaSemana: DIAS_SEMANA[d.getDay()],
    diaSemanaIdx: d.getDay(),
    diaSemanaLabel: DIAS_SEMANA_PT[d.getDay()],
    formatted: params.data_desejada.split('-').reverse().join('/')
  });
} else {
  // Buscar próximos 3 dias úteis (até 14 dias à frente)
  const hoje = new Date();
  hoje.setHours(0, 0, 0, 0);
  let diasEncontrados = 0;
  let diasVerificados = 0;

  while (diasEncontrados < 3 && diasVerificados < 14) {
    const dia = new Date(hoje);
    dia.setDate(dia.getDate() + diasVerificados + 1); // começa de amanhã

    const diaSemanaIdx = dia.getDay();
    // Incluir todos os dias (a jornada será verificada na query)
    const iso = dia.toISOString().split('T')[0];
    datasParaConsultar.push({
      iso: iso,
      diaSemana: DIAS_SEMANA[diaSemanaIdx],
      diaSemanaIdx: diaSemanaIdx,
      diaSemanaLabel: DIAS_SEMANA_PT[diaSemanaIdx],
      formatted: iso.split('-').reverse().join('/')
    });
    diasEncontrados++;
    diasVerificados++;
  }
}

return [{
  json: {
    funcionario_id: params.funcionario_id,
    servico_id: params.servico_id,
    organizacao_id: params.organizacao_id,
    duracao_servico: duracaoServico,
    tolerancia: tolerancia,
    duracao_total: duracaoServico + tolerancia,
    datas: datasParaConsultar,
    buscar_proximos_dias: params.buscar_proximos_dias
  }
}];

// ════════════════════════════════════════════════════════
// CALCULAR HORÁRIOS DISPONÍVEIS
// Algoritmo idêntico ao AgendamentoService.getHorariosDisponiveis()
// Linhas 880-1063 do back-end Java
// ════════════════════════════════════════════════════════

const dadosPrep = $('Preparar Datas').item.json;
const duracaoServico = dadosPrep.duracao_servico;
const tolerancia = dadosPrep.tolerancia;
const duracaoTotal = dadosPrep.duracao_total;
const datasInfo = dadosPrep.datas;

// Obter resultados da query
const rows = $input.all().map(item => item.json).filter(r => r.data_iso);

const DIAS_SEMANA_PT = ['Domingo', 'Segunda-feira', 'Terça-feira', 'Quarta-feira', 'Quinta-feira', 'Sexta-feira', 'Sábado'];

// Função auxiliar: parse time string 'HH:MM:SS' ou 'HH:MM' para minutos desde meia-noite
function timeToMinutes(timeStr) {
  if (!timeStr) return 0;
  const parts = String(timeStr).split(':');
  return parseInt(parts[0]) * 60 + parseInt(parts[1] || 0);
}

// Função auxiliar: minutos para string 'HH:MM'
function minutesToTime(mins) {
  const h = Math.floor(mins / 60);
  const m = mins % 60;
  return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`;
}

// Função auxiliar: parse timestamp para minutos desde meia-noite
function timestampToMinutes(ts) {
  if (!ts) return 0;
  const d = new Date(ts);
  return d.getHours() * 60 + d.getMinutes();
}

// Agrupar resultados por data
const porData = {};
rows.forEach(row => {
  if (row.dia_bloqueado) return; // Ignorar dias bloqueados pela organização

  const key = row.data_iso;
  if (!porData[key]) {
    porData[key] = {
      data_iso: key,
      dia_semana: row.dia_semana,
      periodos: [],
      bloqueios: []
    };
  }

  // Adicionar período de trabalho
  porData[key].periodos.push({
    inicio: timeToMinutes(row.jornada_inicio),
    fim: timeToMinutes(row.jornada_fim)
  });

  // Adicionar bloqueios
  let bloqueios = row.bloqueios || [];
  if (typeof bloqueios === 'string') {
    try { bloqueios = JSON.parse(bloqueios); } catch(e) { bloqueios = []; }
  }
  bloqueios.forEach(b => {
    porData[key].bloqueios.push({
      inicio: timestampToMinutes(b.inicio),
      fim: timestampToMinutes(b.fim),
      tipo: b.tipo
    });
  });
});

// Para cada data, calcular slots disponíveis
const todosHorarios = [];

Object.entries(porData).forEach(([dataIso, dadosDia]) => {
  const dataInfo = datasInfo.find(d => d.iso === dataIso) || {};
  const dataObj = new Date(dataIso + 'T12:00:00');
  const diaSemanaLabel = DIAS_SEMANA_PT[dataObj.getDay()];

  // Verificar se é o dia atual
  const agora = new Date();
  const agoraIso = agora.toISOString().split('T')[0];
  const isDiaAtual = dataIso === agoraIso;
  const minutosAgora = isDiaAtual ? (agora.getHours() * 60 + agora.getMinutes()) : 0;

  // Consolidar bloqueios (remover duplicatas)
  const bloqueiosUnicos = [];
  const bloqueiosVistos = new Set();
  dadosDia.bloqueios.forEach(b => {
    const chave = `${b.inicio}-${b.fim}`;
    if (!bloqueiosVistos.has(chave)) {
      bloqueiosVistos.add(chave);
      bloqueiosUnicos.push(b);
    }
  });

  // Para cada período de trabalho, calcular slots
  dadosDia.periodos.forEach(periodo => {
    const inicioTrabalho = periodo.inicio;
    const fimTrabalho = periodo.fim;

    // Montar lista de bloqueios para este período
    const bloqueiosPeriodo = [];

    // Bloqueio virtual: antes da jornada
    bloqueiosPeriodo.push({ inicio: 0, fim: inicioTrabalho });

    // Bloqueio virtual: horário passado (se dia atual)
    if (isDiaAtual && minutosAgora > inicioTrabalho) {
      bloqueiosPeriodo.push({ inicio: 0, fim: minutosAgora });
    }

    // Bloqueios reais que interceptam este período
    bloqueiosUnicos.forEach(b => {
      const bInicio = Math.max(b.inicio, 0);
      const bFim = Math.min(b.fim, 24 * 60);
      if (bInicio < fimTrabalho && bFim > inicioTrabalho) {
        bloqueiosPeriodo.push({ inicio: bInicio, fim: bFim });
      }
    });

    // Bloqueio virtual: após a jornada
    bloqueiosPeriodo.push({ inicio: fimTrabalho, fim: 24 * 60 });

    // Ordenar bloqueios
    bloqueiosPeriodo.sort((a, b) => a.inicio - b.inicio);

    // Encontrar slots entre bloqueios
    let ponteiro = inicioTrabalho;

    for (const bloqueio of bloqueiosPeriodo) {
      const inicioBloqueio = bloqueio.inicio;
      const fimBloqueio = bloqueio.fim;

      // Verificar espaço antes do bloqueio
      if (ponteiro < inicioBloqueio) {
        let gapMinutos = inicioBloqueio - ponteiro;

        while (gapMinutos >= duracaoTotal) {
          const slotInicio = ponteiro;
          const slotFim = ponteiro + duracaoServico;

          if (slotFim > inicioBloqueio || slotFim > fimTrabalho) break;

          todosHorarios.push({
            data: dataIso,
            data_formatted: dataIso.split('-').reverse().join('/'),
            dia_semana: diaSemanaLabel,
            hora_inicio: minutesToTime(slotInicio),
            hora_fim: minutesToTime(slotFim),
            descricao: `${minutesToTime(slotInicio)} - ${minutesToTime(slotFim)}`
          });

          ponteiro = slotFim + tolerancia;
          gapMinutos = inicioBloqueio - ponteiro;
        }
      }

      // Avançar ponteiro para fim do bloqueio
      if (fimBloqueio > ponteiro) ponteiro = fimBloqueio;
    }

    // Verificar espaço após último bloqueio até fim da jornada
    if (ponteiro < fimTrabalho) {
      let gapFinal = fimTrabalho - ponteiro;

      while (gapFinal >= duracaoTotal) {
        const slotInicio = ponteiro;
        const slotFim = ponteiro + duracaoServico;

        if (slotFim > fimTrabalho) break;

        todosHorarios.push({
          data: dataIso,
          data_formatted: dataIso.split('-').reverse().join('/'),
          dia_semana: diaSemanaLabel,
          hora_inicio: minutesToTime(slotInicio),
          hora_fim: minutesToTime(slotFim),
          descricao: `${minutesToTime(slotInicio)} - ${minutesToTime(slotFim)}`
        });

        ponteiro = slotFim + tolerancia;
        gapFinal = fimTrabalho - ponteiro;
      }
    }
  });
});

// Ordenar por data e hora
todosHorarios.sort((a, b) => {
  if (a.data !== b.data) return a.data.localeCompare(b.data);
  return a.hora_inicio.localeCompare(b.hora_inicio);
});

// Remover duplicatas
const vistos = new Set();
const horariosUnicos = todosHorarios.filter(h => {
  const key = `${h.data}-${h.hora_inicio}`;
  if (vistos.has(key)) return false;
  vistos.add(key);
  return true;
});

// Formatar resposta
if (horariosUnicos.length === 0) {
  // Verificar se não havia jornada para os dias consultados
  const datasConsultadas = datasInfo.map(d => d.formatted).join(', ');
  return [{
    json: {
      response: JSON.stringify({
        horarios: [],
        mensagem: `Não há horários disponíveis para as datas consultadas (${datasConsultadas}). O profissional pode não trabalhar nesses dias ou todos os horários estão ocupados. Tente outra data.`
      })
    }
  }];
}

return [{
  json: {
    response: JSON.stringify({
      horarios: horariosUnicos,
      total: horariosUnicos.length,
      busca_automatica: dadosPrep.buscar_proximos_dias
    })
  }
}];
